-- Create table for the comprehensive skin tone palette
CREATE TABLE public.foundation_palette (
  id UUID NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
  group_name TEXT NOT NULL,
  tone_name TEXT NOT NULL,
  hex_color TEXT NOT NULL,
  swatch_data_uri TEXT,
  created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT now(),
  updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT now()
);

-- Enable RLS
ALTER TABLE public.foundation_palette ENABLE ROW LEVEL SECURITY;

-- Create policy for public read access
CREATE POLICY "Anyone can view foundation palette" 
ON public.foundation_palette 
FOR SELECT 
USING (true);

