-- Create indexes for better performance
CREATE INDEX idx_foundation_palette_group ON public.foundation_palette(group_name);
CREATE INDEX idx_foundation_palette_hex ON public.foundation_palette(hex_color);

-- Add trigger for updated_at
CREATE TRIGGER update_foundation_palette_updated_at
BEFORE UPDATE ON public.foundation_palette
FOR EACH ROW
EXECUTE FUNCTION public.update_user_analysis_updated_at();;
